import{c as a,a0 as n,U as s,j as c,g as i,n as l,o as r,m as d}from"./chunks/framework.Dvkoa_vi.js";const g=JSON.parse('{"title":"Organización del curso","description":"Índice y estructura completa del curso de normalización de la Universidad de Alicante — 25 sesiones de 1 h 30 min.","frontmatter":{"title":"Organización del curso","description":"Índice y estructura completa del curso de normalización de la Universidad de Alicante — 25 sesiones de 1 h 30 min.","outline":"deep"},"headers":[],"relativePath":"organizacion-del-curso.md","filePath":"organizacion-del-curso.md"}'),t={name:"organizacion-del-curso.md"};function u(p,e,m,h,y,b){const o=n("CopyOrDownloadAsMarkdownButtons");return s(),c("div",null,[e[0]||(e[0]=i("div",{style:{display:"none"},hidden:"true","aria-hidden":"true"},"Are you an LLM? You can read better optimized documentation at /curso-normalizacion/organizacion-del-curso.md for this page in Markdown format",-1)),e[1]||(e[1]=i("h1",{id:"organizacion-del-curso",tabindex:"-1"},[l("Organización del curso "),i("a",{class:"header-anchor",href:"#organizacion-del-curso","aria-label":"Permalink to “Organización del curso”"},"​")],-1)),r(o),e[2]||(e[2]=d('<p>El curso consta de <strong>25 sesiones de 1 h 30 min</strong> organizadas en seis bloques temáticos, más una sesión previa de preparación del entorno (no cuenta en la numeración) y un proyecto final transversal.</p><h2 id="sesion-previa-—-preparacion-del-entorno" tabindex="-1">Sesión previa — Preparación del entorno <a class="header-anchor" href="#sesion-previa-—-preparacion-del-entorno" aria-label="Permalink to “Sesión previa — Preparación del entorno”">​</a></h2><p><a href="./00-preparacion/">Bloque 0 · 00-preparacion</a> · <strong>1 h 30 min</strong></p><ul><li>Herramientas a instalar: Git for Windows, Node.js, .NET SDK 10, Visual Studio 2022, VS Code.</li><li>Configuración de Git: identidad (<code>user.name</code>, <code>user.email</code>), <code>autocrlf</code>, editor, rama por defecto.</li><li>Clave SSH: generación RSA, <code>ssh-agent</code> automático en PowerShell, <code>~/.ssh/config</code>.</li><li>Registrar clave pública en el servidor TFS.</li><li>Autenticación HTTPS con TFS y Git Credential Manager.</li><li>Configuración npm: <code>~/.npmrc</code> con PAT (Personal Access Token) codificado en Base64.</li><li>Configuración NuGet: fuentes <code>nuget.org</code>, <code>NUGET UA</code>, <code>ServidorTFS</code> y paquetes locales.</li><li>Clonar un repositorio por SSH y por HTTPS.</li><li>Extensiones de VS Code recomendadas: Vue - Official, C# Dev Kit, i18n Ally, Oracle SQL Developer, Playwright.</li><li>Permiso COPILOT y extensión de accesibilidad.</li></ul><hr><h2 id="bloque-1-—-oracle-sesiones-1-a-5" tabindex="-1">Bloque 1 — Oracle (Sesiones 1 a 5) <a class="header-anchor" href="#bloque-1-—-oracle-sesiones-1-a-5" aria-label="Permalink to “Bloque 1 — Oracle (Sesiones 1 a 5)”">​</a></h2><h3 id="sesion-1-—-fundamentos-oracle" tabindex="-1">Sesión 1 — Fundamentos Oracle <a class="header-anchor" href="#sesion-1-—-fundamentos-oracle" aria-label="Permalink to “Sesión 1 — Fundamentos Oracle”">​</a></h3><ul><li>Arquitectura de dos esquemas: propietario de datos vs usuario de aplicación.</li><li>Cómo se relacionan las tablas, vistas y paquetes con el código .NET.</li><li>Convenciones de nombres en cada capa: base de datos, C# y TypeScript.</li><li>Cómo se traducen los tipos de Oracle a .NET: los casos que requieren atención.</li><li>Cuándo el mapeo es automático y cuándo hay que hacerlo a mano.</li><li>Cómo se controla el acceso: qué puede hacer el usuario de aplicación y qué no.</li><li>Buenas prácticas de diseño de esquema.</li></ul><h3 id="sesion-2-—-ejercicio-inspeccion-del-schema-y-diseno-de-un-catalogo" tabindex="-1">Sesión 2 — Ejercicio: inspección del schema y diseño de un catálogo <a class="header-anchor" href="#sesion-2-—-ejercicio-inspeccion-del-schema-y-diseno-de-un-catalogo" aria-label="Permalink to “Sesión 2 — Ejercicio: inspección del schema y diseño de un catálogo”">​</a></h3><ul><li>Inspeccionar el schema con <code>oracle-schema-extractor</code> y SQL Developer.</li><li>Diseñar e implementar un catálogo simple respetando las convenciones del bloque.</li></ul><h3 id="sesion-3-—-tablas-vistas-y-paquetes" tabindex="-1">Sesión 3 — Tablas, vistas y paquetes <a class="header-anchor" href="#sesion-3-—-tablas-vistas-y-paquetes" aria-label="Permalink to “Sesión 3 — Tablas, vistas y paquetes”">​</a></h3><ul><li>Tablas: PK, FK, restricciones <code>CHECK</code>, índices y comentarios; tablespaces <code>OTRAS_APP_DAT</code> / <code>OTRAS_APP_IND</code>.</li><li>Vistas orientadas al usuario WEB: alias para el automapeo .NET, sin <code>SELECT *</code>, uso del Explain Plan.</li><li>Operaciones estándar de un package CRUD: <code>INSERTAR</code>, <code>ACTUALIZAR</code>, <code>ELIMINAR</code>, <code>LISTAR</code>, <code>OBTENER_POR_ID</code>.</li><li>Ocultar y mostrar registros usando eliminación lógica con un campo <code>ACTIVO</code> y filtros en la vista.</li><li>Flujo completo: <code>TABLA → VISTA → DTO .NET → API → Vue</code>.</li></ul><h3 id="sesion-4-—-ejercicio-diseno-de-vistas" tabindex="-1">Sesión 4 — Ejercicio: diseño de vistas <a class="header-anchor" href="#sesion-4-—-ejercicio-diseno-de-vistas" aria-label="Permalink to “Sesión 4 — Ejercicio: diseño de vistas”">​</a></h3><ul><li>Diseñar <code>VRES_FRANJA_HORARIO</code> y <code>VRES_HORARIO_DIA</code> con alias listos para el automapeo.</li><li>Validar con Explain Plan y consultar desde el usuario WEB.</li></ul><h3 id="sesion-5-—-ejercicio-procedimientos-en-paquetes" tabindex="-1">Sesión 5 — Ejercicio: procedimientos en paquetes <a class="header-anchor" href="#sesion-5-—-ejercicio-procedimientos-en-paquetes" aria-label="Permalink to “Sesión 5 — Ejercicio: procedimientos en paquetes”">​</a></h3><ul><li>Implementar <code>ACTUALIZAR_BLOQUEADO</code>, <code>CREAR_HORARIO_DIA</code> y <code>CREAR_RESERVA</code>.</li><li>Detección de solapamiento entre reservas en el propio paquete.</li></ul><hr><h2 id="bloque-2-—-net-core-10-sesiones-6-a-8" tabindex="-1">Bloque 2 — .NET Core 10 (Sesiones 6 a 8) <a class="header-anchor" href="#bloque-2-—-net-core-10-sesiones-6-a-8" aria-label="Permalink to “Bloque 2 — .NET Core 10 (Sesiones 6 a 8)”">​</a></h2><h3 id="sesion-6-—-introduccion-a-net" tabindex="-1">Sesión 6 — Introducción a .NET <a class="header-anchor" href="#sesion-6-—-introduccion-a-net" aria-label="Permalink to “Sesión 6 — Introducción a .NET”">​</a></h3><ul><li>Crear proyecto desde VS 2022, configuración inicial y uso de GIT.</li><li>¿Qué es .NET? Versiones y novedades de .NET 10.</li><li>Anatomía del proyecto (<code>PlantillaMVCCore</code>): estructura de carpetas y archivos clave.</li><li><code>Program.cs</code>: registro de servicios y pipeline de middleware.</li><li>Inyección de dependencias: interfaz, implementación y <code>ServicesExtensionsApp</code>.</li><li>Ciclos de vida: <code>AddTransient</code>, <code>AddScoped</code>, <code>AddSingleton</code>.</li><li>C# útil en el contexto del curso: pattern matching, null-conditional, null-coalescing, tuplas internas.</li><li>Novedades reales de .NET 10 y C# 14 con impacto práctico: OpenAPI en ASP.NET Core, <code>dotnet test</code> con Microsoft.Testing.Platform, null-conditional assignment y <code>field</code> backed properties.</li></ul><h3 id="sesion-7-—-modelos-y-primer-api" tabindex="-1">Sesión 7 — Modelos y primer API <a class="header-anchor" href="#sesion-7-—-modelos-y-primer-api" aria-label="Permalink to “Sesión 7 — Modelos y primer API”">​</a></h3><ul><li>Modelos (DTO): qué son y convenciones de nombres.</li><li>Anatomía de un controlador API.</li><li>Verbos HTTP y códigos de estado.</li><li>Diseño de respuestas de la API: respuestas tipadas (<code>Ok()</code>, <code>NotFound()</code>, <code>BadRequest()</code>) frente a respuestas uniformes, ventajas e inconvenientes.</li><li>Probar la API sin base de datos.</li><li>Llamar a la API desde Vue con TypeScript.</li></ul><h3 id="sesion-8-—-servicios-y-acceso-a-oracle" tabindex="-1">Sesión 8 — Servicios y acceso a Oracle <a class="header-anchor" href="#sesion-8-—-servicios-y-acceso-a-oracle" aria-label="Permalink to “Sesión 8 — Servicios y acceso a Oracle”">​</a></h3><ul><li>Separar la lógica en capas: controlador, servicio e interfaz.</li><li>Cómo acceder a Oracle desde .NET y mapear los datos a objetos.</li><li>Cómo registrar y conectar las piezas entre sí.</li><li>Flujo completo de una petición: desde Vue hasta Oracle y de vuelta.</li></ul><blockquote><p>Validación avanzada, gestión global de errores, DataTable server-side y documentación OpenAPI se cubren de extremo a extremo en el bloque <strong>Integración</strong> (sesiones 14-17).</p></blockquote><hr><h2 id="bloque-3-—-vue-3-con-typescript-sesiones-9-a-13" tabindex="-1">Bloque 3 — Vue 3 con TypeScript (Sesiones 9 a 13) <a class="header-anchor" href="#bloque-3-—-vue-3-con-typescript-sesiones-9-a-13" aria-label="Permalink to “Bloque 3 — Vue 3 con TypeScript (Sesiones 9 a 13)”">​</a></h2><h3 id="sesion-9-—-vue-3-typescript-y-primer-componente" tabindex="-1">Sesión 9 — Vue 3, TypeScript y primer componente <a class="header-anchor" href="#sesion-9-—-vue-3-typescript-y-primer-componente" aria-label="Permalink to “Sesión 9 — Vue 3, TypeScript y primer componente”">​</a></h3><ul><li>¿Por qué Vue 3 en la UA?</li><li>Estructura de un <code>.vue</code>: script, template y style.</li><li>Vistas vs componentes.</li><li>TypeScript básico: tipos, <code>const</code>/<code>let</code>, union types, <code>any</code> vs <code>unknown</code>.</li><li>Reactividad con <code>ref</code> y <code>reactive</code>.</li><li>Interpolación en el template.</li><li>Depuración básica con Vue Devtools.</li></ul><h3 id="sesion-10-—-directivas-eventos-y-datos" tabindex="-1">Sesión 10 — Directivas, eventos y datos <a class="header-anchor" href="#sesion-10-—-directivas-eventos-y-datos" aria-label="Permalink to “Sesión 10 — Directivas, eventos y datos”">​</a></h3><ul><li>Interfaces TypeScript: contratos de datos.</li><li>Funciones tipadas en componentes Vue.</li><li>Renderizado condicional: <code>v-if</code> vs <code>v-show</code>.</li><li>Renderizado de listas con <code>v-for</code> y <code>:key</code>.</li><li>Vincular atributos con <code>v-bind</code> y clases CSS dinámicas.</li><li>Enlace bidireccional con <code>v-model</code>.</li><li>Eventos del DOM y modificadores.</li><li>Métodos de arrays: <code>.map()</code>, <code>.filter()</code>, <code>.find()</code>, <code>.reduce()</code>.</li><li>Spread, destructuring, optional chaining y nullish coalescing.</li></ul><h3 id="sesion-11-—-componentes-y-comunicacion" tabindex="-1">Sesión 11 — Componentes y comunicación <a class="header-anchor" href="#sesion-11-—-componentes-y-comunicacion" aria-label="Permalink to “Sesión 11 — Componentes y comunicación”">​</a></h3><ul><li>Propiedades computadas con <code>computed</code>.</li><li>Patrón de formulario: entrada → derivado → acción.</li><li>Comunicación padre → hijo con Props (<code>defineProps</code>).</li><li>Comunicación hijo → padre con Emits (<code>defineEmits</code>).</li><li>Comunicación bidireccional con <code>defineModel</code>.</li><li>Watchers: <code>watch</code> y <code>watchEffect</code>.</li><li>Lifecycle hooks y carga asíncrona con <code>onMounted</code>.</li><li>Slots: contenido dinámico y layouts reutilizables.</li></ul><h3 id="sesion-12-—-arquitectura-de-componentes-y-servicios" tabindex="-1">Sesión 12 — Arquitectura de componentes y servicios <a class="header-anchor" href="#sesion-12-—-arquitectura-de-componentes-y-servicios" aria-label="Permalink to “Sesión 12 — Arquitectura de componentes y servicios”">​</a></h3><ul><li>Composables vs Servicios: cuándo usar cada uno.</li><li>Arquitectura Vista → Composable → Servicio.</li><li>Herramientas de depuración: Vue Devtools, <code>vue-tsc</code> y Network.</li></ul><h3 id="sesion-13-—-otros-componentes-internos" tabindex="-1">Sesión 13 — Otros componentes internos <a class="header-anchor" href="#sesion-13-—-otros-componentes-internos" aria-label="Permalink to “Sesión 13 — Otros componentes internos”">​</a></h3><ul><li><code>PopUpModal</code>, <code>DialogModal</code>, <code>SpinnerModal</code>: modales reutilizables y patrones de uso.</li><li><code>BotonLoading</code> y directiva <code>v-loading</code>.</li><li><code>useToast</code> para notificaciones, <code>Checkbox3estados</code>.</li><li><code>Teleport</code>: renderizar elementos fuera del árbol de componentes.</li></ul><hr><h2 id="bloque-4-—-integracion-full-stack-sesiones-14-a-17" tabindex="-1">Bloque 4 — Integración full-stack (Sesiones 14 a 17) <a class="header-anchor" href="#bloque-4-—-integracion-full-stack-sesiones-14-a-17" aria-label="Permalink to “Bloque 4 — Integración full-stack (Sesiones 14 a 17)”">​</a></h2><h3 id="sesion-14-—-llamadas-a-la-api-y-autenticacion" tabindex="-1">Sesión 14 — Llamadas a la API y autenticación <a class="header-anchor" href="#sesion-14-—-llamadas-a-la-api-y-autenticacion" aria-label="Permalink to “Sesión 14 — Llamadas a la API y autenticación”">​</a></h3><ul><li>Cómo funciona la autenticación: CAS, cookies de sesión y tokens JWT.</li><li>Claims del usuario: cómo leerlos en .NET y en Vue.</li><li>Estados de carga: spinners y variables reactivas en Vue; cuándo usar <code>onMounted</code> vs <code>watchEffect</code>.</li><li>Llamadas a la API con <code>useAxios</code> y <code>HttpApi</code>: verbos, modos y gestión de errores.</li><li>Explorar y probar la API con OpenAPI y Scalar.</li></ul><h3 id="sesion-15-—-validacion-en-todas-las-capas" tabindex="-1">Sesión 15 — Validación en todas las capas <a class="header-anchor" href="#sesion-15-—-validacion-en-todas-las-capas" aria-label="Permalink to “Sesión 15 — Validación en todas las capas”">​</a></h3><ul><li>Validaciones simples con DataAnnotations.</li><li>Validaciones complejas con FluentValidation: reglas cruzadas y dependientes.</li><li>Uso del ModelState para devolver errores específicos por campo.</li><li>Cómo el servidor devuelve errores de validación y cómo Vue los pinta en el formulario.</li><li>Validación de formularios en Vue con <code>useGestionFormularios</code>.</li></ul><h3 id="sesion-16-—-gestion-de-errores-de-extremo-a-extremo" tabindex="-1">Sesión 16 — Gestión de errores de extremo a extremo <a class="header-anchor" href="#sesion-16-—-gestion-de-errores-de-extremo-a-extremo" aria-label="Permalink to “Sesión 16 — Gestión de errores de extremo a extremo”">​</a></h3><ul><li>Cómo se propaga un error desde Oracle hasta el usuario.</li><li>Tipos de excepción UA: <code>BDException</code> (Usuario/Sistema), <code>AppException</code>, <code>InfoException</code>, <code>MantenimientoException</code>.</li><li><code>ErrorHandlerMiddleware</code> de <code>PlantillaMVCCore.Errores</code>: decisión JSON vs MVC, notificación por correo, fallback a v1.x.</li><li><code>AddClaseErrores()</code>: enriquecedores de petición, usuario CAS y aplicación; throttling y <code>EnvioEnDesarrollo</code>.</li><li>Notificaciones al usuario: toasts de confirmación, error e información.</li><li>Modales de confirmación antes de operaciones destructivas.</li></ul><h3 id="sesion-17-—-datatable-de-extremo-a-extremo" tabindex="-1">Sesión 17 — DataTable de extremo a extremo <a class="header-anchor" href="#sesion-17-—-datatable-de-extremo-a-extremo" aria-label="Permalink to “Sesión 17 — DataTable de extremo a extremo”">​</a></h3><ul><li>Listado simple vs DataTable con paginación en servidor: cuándo usar cada uno.</li><li>Lado servidor .NET: <code>ClaseCrudUtils</code>, <code>CamposFiltros</code>, paginación, filtros y ordenación.</li><li>Lado cliente Vue: componente <code>vueua-datatable</code> y su configuración.</li><li>Conectar las dos partes: del endpoint al componente en una sola sesión.</li></ul><hr><h2 id="bloque-5-—-sesiones-avanzadas-sesiones-18-a-25" tabindex="-1">Bloque 5 — Sesiones avanzadas (Sesiones 18 a 25) <a class="header-anchor" href="#bloque-5-—-sesiones-avanzadas-sesiones-18-a-25" aria-label="Permalink to “Bloque 5 — Sesiones avanzadas (Sesiones 18 a 25)”">​</a></h2><h3 id="sesion-18-—-internacionalizacion" tabindex="-1">Sesión 18 — Internacionalización <a class="header-anchor" href="#sesion-18-—-internacionalizacion" aria-label="Permalink to “Sesión 18 — Internacionalización”">​</a></h3><ul><li>Localización con <code>IStringLocalizer</code> y archivos <code>.resx</code>: organización por idioma y acceso desde .NET y Vue.</li><li>Archivos de traducción con <code>vue-i18n</code> y cambio de idioma.</li><li>Acceso al idioma del usuario desde el token JWT en .NET.</li><li>Extensión i18n Ally para gestionar traducciones desde VS Code.</li></ul><h3 id="sesion-19-—-seguridad-menus-y-perfiles-de-aplicacion" tabindex="-1">Sesión 19 — Seguridad, menús y perfiles de aplicación <a class="header-anchor" href="#sesion-19-—-seguridad-menus-y-perfiles-de-aplicacion" aria-label="Permalink to “Sesión 19 — Seguridad, menús y perfiles de aplicación”">​</a></h3><ul><li>Autorización basada en roles y políticas en .NET.</li><li>Perfiles de aplicación: qué ve cada usuario según su rol.</li><li>Menú dinámico según permisos: cómo construirlo en Vue.</li><li>Layout general de la aplicación: cabecera, menú lateral y pie.</li><li>Protección de rutas en Vue Router y de endpoints en .NET.</li><li>Verificación múltiple de datos en cliente, servidor y paquete Oracle.</li></ul><h3 id="sesion-20-—-estado-global-y-persistencia" tabindex="-1">Sesión 20 — Estado global y persistencia <a class="header-anchor" href="#sesion-20-—-estado-global-y-persistencia" aria-label="Permalink to “Sesión 20 — Estado global y persistencia”">​</a></h3><ul><li>Estado global con Pinia: cuándo elevar el estado y cuándo mantenerlo local.</li><li>Persistencia de estado: <code>localStorage</code> vs <code>sessionStorage</code> vs cookies.</li><li>Patrones de store: stores simples vs stores con acciones asíncronas.</li><li><code>provide</code> / <code>inject</code> para dependencias transversales.</li></ul><h3 id="sesion-21-—-tests-y-calidad-de-codigo" tabindex="-1">Sesión 21 — Tests y calidad de código <a class="header-anchor" href="#sesion-21-—-tests-y-calidad-de-codigo" aria-label="Permalink to “Sesión 21 — Tests y calidad de código”">​</a></h3><ul><li>Tests unitarios en .NET con xUnit: controladores y servicios.</li><li>Tests de integración con <code>WebApplicationFactory</code>.</li><li>Pruebas manuales de la API con archivos <code>.http</code>: variables, entornos y request variables.</li><li><code>httpRepl</code> como alternativa CLI para explorar la API y ejecutar scripts.</li><li>Automatizar comprobaciones de API para IA con <code>Invoke-RestMethod</code> o <code>curl</code>.</li><li>ActionFilters: qué son y casos de uso.</li><li>Naming JSON: camelCase vs PascalCase.</li><li>Patrón GET comprobación + POST ejecución con token.</li></ul><h3 id="sesion-22-—-trabajo-con-ficheros" tabindex="-1">Sesión 22 — Trabajo con ficheros <a class="header-anchor" href="#sesion-22-—-trabajo-con-ficheros" aria-label="Permalink to “Sesión 22 — Trabajo con ficheros”">​</a></h3><ul><li>Subida de ficheros desde Vue al servidor .NET.</li><li>Almacenamiento de ficheros en Oracle (BLOB) y en disco.</li><li>Descarga y visualización de ficheros desde Vue.</li><li>Validaciones de tipo, tamaño y nombre en cliente y servidor.</li><li>Gestión de recursos adjuntos en un CRUD completo.</li></ul><h3 id="sesion-23-—-logs-y-diagnostico" tabindex="-1">Sesión 23 — Logs y diagnóstico <a class="header-anchor" href="#sesion-23-—-logs-y-diagnostico" aria-label="Permalink to “Sesión 23 — Logs y diagnóstico”">​</a></h3><ul><li>Logging estructurado con Serilog: niveles y cuándo usar cada uno.</li><li>Sinks disponibles: consola, Oracle, fichero y correo electrónico.</li><li>Enriquecimiento del log con datos del usuario y la petición.</li><li>Consultas de diagnóstico sobre los logs almacenados en Oracle.</li><li>VS Code como IDE alternativo: configuración y depuración de .NET.</li></ul><h3 id="sesion-24-—-accesibilidad-y-cumplimiento-normativo" tabindex="-1">Sesión 24 — Accesibilidad y cumplimiento normativo <a class="header-anchor" href="#sesion-24-—-accesibilidad-y-cumplimiento-normativo" aria-label="Permalink to “Sesión 24 — Accesibilidad y cumplimiento normativo”">​</a></h3><ul><li>Por qué importa la accesibilidad y qué exige el ENS.</li><li>WCAG 2.1 nivel AA: los criterios más relevantes para aplicaciones internas.</li><li>Herramientas de auditoría: axe, Lighthouse.</li><li>Cómo aplicar accesibilidad en componentes Vue: <code>aria-*</code>, roles, foco.</li><li>Normalización de datos y cumplimiento ENS.</li><li>Documentación técnica, manual de usuario e integración con CAU.</li><li>Uso de la extensión de accesibilidad de la Unidad de Accesibilidad.</li></ul><h3 id="sesion-25-—-copilot-y-organizacion-del-proyecto" tabindex="-1">Sesión 25 — Copilot y organización del proyecto <a class="header-anchor" href="#sesion-25-—-copilot-y-organizacion-del-proyecto" aria-label="Permalink to “Sesión 25 — Copilot y organización del proyecto”">​</a></h3><ul><li>Copilot en modo agente: cómo delegar tareas completas.</li><li>Prompts efectivos para generación de código en el contexto del proyecto.</li><li>Revisión crítica del código generado: qué aceptar y qué corregir.</li><li>Organización del repositorio: ramas, convenciones de commits y flujo de trabajo.</li><li>Snippets de VS Code: crear y compartir fragmentos reutilizables.</li><li>Retrospectiva del curso: qué hemos construido y cómo seguir aprendiendo.</li></ul><hr><h2 id="proyecto-final-—-aplicacion-de-reservas" tabindex="-1">Proyecto final — Aplicación de reservas <a class="header-anchor" href="#proyecto-final-—-aplicacion-de-reservas" aria-label="Permalink to “Proyecto final — Aplicación de reservas”">​</a></h2><p>A lo largo de las 25 sesiones el alumno construye una <strong>aplicación de reservas</strong> en cuatro módulos progresivos:</p><ol><li><strong>Tipo de recurso</strong> — Hilo conductor del curso. El material lo construye en clase.</li><li><strong>Recurso</strong> — Ejercicio guiado: aplica el patrón con auditoría y seguridad.</li><li><strong>Horario</strong> — Profundización: objetos complejos y estado compartido.</li><li><strong>Reserva</strong> — Cierre integrador: combina todo con las sesiones avanzadas.</li></ol><p>Cada módulo tiene su propia rama de Git (<code>tiporecurso-&lt;nombre&gt;</code>, <code>recurso-&lt;nombre&gt;</code>, <code>horario-&lt;nombre&gt;</code>, <code>reserva-&lt;nombre&gt;</code>) y cada día arranca con la solución del día anterior publicada en <code>master</code>.</p><p>Mapa maestro, hitos por sesión y criterios de aceptación en: <a href="./06-proyecto-final/">Proyecto final del curso</a>.</p>',71))])}const S=a(t,[["render",u]]);export{g as __pageData,S as default};
